#define NUM_BINS 1000
#define NUM_THREADS 4

int histogram[NUM_BINS];

void compute_histogram_false_sharing(int* data, int n) {
 #pragma omp parallel num_threads(NUM_THREADS)
 {
 int tid = omp_get_thread_num();
 int chunk = n / NUM_THREADS;
 int start = tid * chunk;
 int end = (tid == NUM_THREADS-1) ? n : start + chunk;

 for (int i = start; i < end; i++) {
 int bin = data[i] % NUM_BINS;
 histogram[bin]++; // False sharing: adjacent bins may share cache line
 }
 }
}

#define CACHE_LINE_SIZE 64
#define NUM_BINS 1000
#define NUM_THREADS 4

// Padded structure - each bin occupies its own cache line
typedef struct {
 int count;
 char pad[CACHE_LINE_SIZE - sizeof(int)];
} PaddedCounter;

PaddedCounter histogram[NUM_BINS];

void compute_histogram_padded(int* data, int n) {
 #pragma omp parallel num_threads(NUM_THREADS)
 {
 int tid = omp_get_thread_num();
 int chunk = n / NUM_THREADS;
 int start = tid * chunk;
 int end = (tid == NUM_THREADS-1) ? n : start + chunk;

 for (int i = start; i < end; i++) {
 int bin = data[i] % NUM_BINS;
 histogram[bin].count++; // No false sharing - separate cache lines
 }
 }
}

#define NUM_THREADS 4

double array_sum_false_sharing_free(double* a, int n) {
 double result = 0.0;
 double local_sums[NUM_THREADS];

 #pragma omp parallel num_threads(NUM_THREADS)
 {
 int tid = omp_get_thread_num();
 local_sums[tid] = 0.0; // Each thread has private accumulator

 #pragma omp for
 for (int i = 0; i < n; i++) {
 local_sums[tid] += a[i]; // Write to thread-local location
 }

 // Combine at end - only one atomic operation per thread
 #pragma omp atomic
 result += local_sums[tid];
 }

 return result;
}

// Equivalent using OpenMP reduction (recommended approach)
double array_sum_reduction(double* a, int n) {
 double sum = 0.0;

 #pragma omp parallel for reduction(+:sum)
 for (int i = 0; i < n; i++) {
 sum += a[i];
 }

 return sum;
}
